import { FormEvent, useState } from 'react'
import './App.css'

type CreateLinkResponse = {
  short_code: string
  short_url: string
  original_url: string
}

const URL_ERROR_MESSAGE = 'URL must start with http:// or https://'

function App() {
  const [url, setUrl] = useState('')
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [shortLink, setShortLink] = useState<CreateLinkResponse | null>(null)
  const [copyStatus, setCopyStatus] = useState('')

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault()

    const trimmedUrl = url.trim()
    if (!trimmedUrl.match(/^https?:\/\//)) {
      setError(URL_ERROR_MESSAGE)
      setShortLink(null)
      return
    }

    setIsLoading(true)
    setError('')
    setCopyStatus('')

    try {
      const response = await fetch('/api/links', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: trimmedUrl }),
      })

      const body = (await response.json()) as CreateLinkResponse & { errors?: string[] }

      if (!response.ok) {
        setShortLink(null)
        setError(body.errors?.[0] ?? 'Unable to shorten URL')
        return
      }

      setShortLink(body)
    } catch {
      setShortLink(null)
      setError('Unable to shorten URL')
    } finally {
      setIsLoading(false)
    }
  }

  const handleCopy = async () => {
    if (!shortLink) {
      return
    }

    await navigator.clipboard.writeText(shortLink.short_url)
    setCopyStatus('Copied!')
  }

  return (
    <main className="app">
      <h1>Link Shortener</h1>
      <form className="shorten-form" onSubmit={handleSubmit}>
        <label htmlFor="url-input">URL</label>
        <input
          id="url-input"
          type="url"
          value={url}
          onChange={(event) => setUrl(event.target.value)}
          placeholder="https://example.com/long-path"
        />
        <button type="submit" disabled={isLoading}>
          {isLoading ? 'Shortening...' : 'Shorten'}
        </button>
      </form>

      {error && (
        <p className="error" role="alert">
          {error}
        </p>
      )}

      {shortLink && (
        <section className="result" aria-live="polite">
          <p>Short link:</p>
          <a href={shortLink.short_url}>{shortLink.short_url}</a>
          <button type="button" onClick={handleCopy}>
            Copy
          </button>
          {copyStatus && <span>{copyStatus}</span>}
        </section>
      )}
    </main>
  )
}

export default App

