import { useState, type FormEvent } from 'react'
import './App.css'

type CreateLinkResponse = {
  short_code: string
  short_url: string
  original_url: string
}

const URL_ERROR_MESSAGE = 'URL must start with http:// or https://'

function App() {
  const [url, setUrl] = useState('')
  const [error, setError] = useState('')
  const [isLoading, setIsLoading] = useState(false)
  const [shortLink, setShortLink] = useState<CreateLinkResponse | null>(null)
  const [copyStatus, setCopyStatus] = useState('')

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault()

    const trimmedUrl = url.trim()
    if (!trimmedUrl.match(/^https?:\/\//)) {
      setError(URL_ERROR_MESSAGE)
      setShortLink(null)
      return
    }

    setIsLoading(true)
    setError('')
    setCopyStatus('')

    try {
      const response = await fetch('/api/links', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: trimmedUrl }),
      })

      const body = (await response.json()) as CreateLinkResponse & { errors?: string[] }

      if (!response.ok) {
        setShortLink(null)
        setError(body.errors?.[0] ?? 'Unable to shorten URL')
        return
      }

      setShortLink(body)
    } catch {
      setShortLink(null)
      setError('Unable to shorten URL')
    } finally {
      setIsLoading(false)
    }
  }

  const handleCopy = async () => {
    if (!shortLink) {
      return
    }

    await navigator.clipboard.writeText(shortLink.short_url)
    setCopyStatus('Copied!')
  }

  return (
    <main className="app">
      <h1>Link Shortener</h1>
      <form className="shorten-form" onSubmit={handleSubmit}>
        <label htmlFor="url-input">URL</label>
        <input
          id="url-input"
          type="url"
          value={url}
          onChange={(event) => setUrl(event.target.value)}
          placeholder="https://example.com/long-path"
        />
        <button type="submit" disabled={isLoading}>
          {isLoading ? 'Shortening...' : 'Shorten'}
        </button>
      </form>

      {error && (
        <p className="error" role="alert">
          {error}
        </p>
      )}

      {shortLink && (
        <section className="result" aria-live="polite">
          <p>Short link:</p>
          <a href={shortLink.short_url}>{shortLink.short_url}</a>
          <button type="button" onClick={handleCopy}>
            Copy
          </button>
          {copyStatus && <span>{copyStatus}</span>}
        </section>
      )}
    </main>
  )
}

export default App

.app {
  max-width: 720px;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

h1 {
  margin-bottom: 1rem;
}

.shorten-form {
  display: grid;
  gap: 0.5rem;
}

.shorten-form input,
.shorten-form button {
  font: inherit;
  padding: 0.6rem 0.75rem;
}

.shorten-form button {
  width: fit-content;
}

.error {
  color: #b91c1c;
  margin-top: 1rem;
}

.result {
  margin-top: 1rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  flex-wrap: wrap;
}

import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'

import App from './App'

describe('App', () => {
  const fetchMock = vi.fn()

  beforeEach(() => {
    fetchMock.mockReset()
    vi.stubGlobal('fetch', fetchMock)
  })

  it('shows URL input and shorten button', () => {
    render(<App />)

    expect(screen.getByLabelText(/url/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /shorten/i })).toBeInTheDocument()
  })

  it('shows a validation error for non-http URL', async () => {
    const user = userEvent.setup()
    render(<App />)

    await user.type(screen.getByLabelText(/url/i), 'ftp://example.com')
    await user.click(screen.getByRole('button', { name: /shorten/i }))

    expect(screen.getByText(/must start with http:\/\/ or https:\/\//i)).toBeInTheDocument()
    expect(fetchMock).not.toHaveBeenCalled()
  })

  it('creates and displays a short link, then copies it', async () => {
    const user = userEvent.setup()
    const clipboardSpy = vi.spyOn(navigator.clipboard, 'writeText').mockResolvedValue()

    fetchMock.mockResolvedValue({
      ok: true,
      json: async () => ({
        short_code: 'abc123',
        short_url: 'http://localhost:3000/abc123',
        original_url: 'https://example.com/long-path',
      }),
    })

    render(<App />)

    await user.type(screen.getByLabelText(/url/i), 'https://example.com/long-path')
    await user.click(screen.getByRole('button', { name: /shorten/i }))

    await waitFor(() => expect(fetchMock).toHaveBeenCalledTimes(1))

    expect(screen.getByRole('link', { name: 'http://localhost:3000/abc123' })).toBeInTheDocument()

    await user.click(screen.getByRole('button', { name: /copy/i }))

    await waitFor(() => {
      expect(clipboardSpy).toHaveBeenCalledWith('http://localhost:3000/abc123')
    })
  })
})

