import { render, screen, waitFor, within } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'

import App from './App'

describe('App', () => {
  const fetchMock = vi.fn()

  beforeEach(() => {
    fetchMock.mockReset()
    vi.stubGlobal('fetch', fetchMock)
  })

  it('shows URL input and shorten button', () => {
    fetchMock.mockResolvedValue({ ok: true, json: async () => [] })

    render(<App />)

    expect(screen.getByLabelText(/url/i)).toBeInTheDocument()
    expect(screen.getByRole('button', { name: /shorten/i })).toBeInTheDocument()
  })

  it('shows recent links on page load', async () => {
    fetchMock.mockResolvedValue({
      ok: true,
      json: async () => [
        {
          short_code: 'abc123',
          original_url:
            'https://example.com/this-is-a-very-long-url-that-should-be-truncated-in-the-list-view',
          click_count: 4,
          created_at: '2026-04-12T10:30:00Z',
        },
      ],
    })

    render(<App />)

    expect(await screen.findByRole('link', { name: 'http://localhost:3000/abc123' })).toBeInTheDocument()
    expect(screen.getByText('https://example.com/this-is-a-very-long-url-that-should-b...')).toBeInTheDocument()
    expect(screen.getByText(/Clicks: 4/)).toBeInTheDocument()
    expect(screen.getByText(/Created: 2026-04-12/)).toBeInTheDocument()
  })

  it('shows a validation error for non-http URL', async () => {
    const user = userEvent.setup()
    fetchMock.mockResolvedValue({ ok: true, json: async () => [] })

    render(<App />)

    await user.type(screen.getByLabelText(/url/i), 'ftp://example.com')
    await user.click(screen.getByRole('button', { name: /shorten/i }))

    expect(screen.getByText(/must start with http:\/\/ or https:\/\//i)).toBeInTheDocument()
    expect(fetchMock).toHaveBeenCalledTimes(1)
  })

  it('creates and displays a short link, then copies it', async () => {
    const user = userEvent.setup()
    const clipboardSpy = vi.spyOn(navigator.clipboard, 'writeText').mockResolvedValue()

    fetchMock
      .mockResolvedValueOnce({ ok: true, json: async () => [] })
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          short_code: 'abc123',
          short_url: 'http://localhost:3000/abc123',
          original_url: 'https://example.com/long-path',
        }),
      })
      .mockResolvedValueOnce({
        ok: true,
        json: async () => [
          {
            short_code: 'abc123',
            original_url: 'https://example.com/long-path',
            click_count: 0,
            created_at: '2026-04-12T10:30:00Z',
          },
        ],
      })

    render(<App />)

    await user.type(screen.getByLabelText(/url/i), 'https://example.com/long-path')
    await user.click(screen.getByRole('button', { name: /shorten/i }))

    await waitFor(() => expect(fetchMock).toHaveBeenCalledTimes(3))

    const resultSection = screen.getByText('Short link:').closest('section')
    expect(resultSection).not.toBeNull()

    const resultLink = within(resultSection as HTMLElement).getByRole('link', {
      name: 'http://localhost:3000/abc123',
